package main

import (
	"fmt"
	"sort"
)

func linearSearch(arr []int, target int) int {
	for i, v := range arr {
		if v == target {
			return i
		}
	}
	return -1
}

func binarySearch(arr []int, target int) int {
	left, right := 0, len(arr)-1

	for left <= right {
		mid := (left + right) / 2

		if arr[mid] == target {
			return mid
		} else if arr[mid] < target {
			left = mid + 1
		} else {
			right = mid - 1
		}
	}
	return -1
}

func main() {
	numbers := []int{4, 12, 7, 23, 9, 1, 18}
	target := 23

	linearResult := linearSearch(numbers, target)
	fmt.Println("Dogrusal arama:", target, "indeks", linearResult, "'de bulundu")

	// Binary arama icin dizi kopyalanip siralanmali
	sortedNumbers := make([]int, len(numbers))
	copy(sortedNumbers, numbers)
	sort.Ints(sortedNumbers)

	binaryResult := binarySearch(sortedNumbers, target)
	fmt.Println("Binary arama:", target, "indeks", binaryResult, "'de bulundu")

	notFound := linearSearch(numbers, 99)
	fmt.Println("\n99 araniyor (bulunamayacak):", notFound)
}
